# Geometry utilities module - provides shapes and geometric operations

# PI constant (since math module is not available)
PI: float = 3.14159

# Manual sqrt implementation using binary search approximation
def sqrt(n: float) -> float:
    if n < 0.0:
        raise ValueError("Cannot compute square root of negative number")
    if n == 0.0:
        return 0.0

    guess: float = n
    epsilon: float = 0.00001

    while abs(guess * guess - n) > epsilon:
        guess = (guess + n / guess) / 2.0

    return guess

# Return the absolute value of a float
def abs_float(x: float) -> float:
    if x < 0.0:
        return -x
    return x

class Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        # Use ** 0.5 for square root
        return (dx * dx + dy * dy) ** 0.5

class Rectangle:
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle:
    radius: float

    def __init__(self, radius: float):
        self.radius = radius

    def area(self) -> float:
        return PI * self.radius * self.radius

    def circumference(self) -> float:
        return 2.0 * PI * self.radius

def calculate_diagonal(rect: Rectangle) -> float:
    return sqrt(rect.width * rect.width + rect.height * rect.height)

def is_square(rect: Rectangle) -> bool:
    return rect.width == rect.height

def create_unit_square() -> Rectangle:
    return Rectangle(1.0, 1.0)
